#pragma once

#include <cuda_runtime.h>
#include <curand_kernel.h>
#include <stdint.h>

// Constants
#define VOCAB_SIZE 129280

// Kernel declaration for random state initialization
void init_random_states_kernel(
    curandState* states,
    int batch_size,
    unsigned long long seed,
    cudaStream_t stream
);

// Kernel declaration for sorting probabilities per row
void sort_probs_kernel(
    float* probs,
    int* indices,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
);

// Kernel declaration for top-k top-p sampling
void launch_top_k_top_p_sampling_kernel(
    const float* probs_sorted,
    const int* indices_sorted,
    const int* top_k,
    const float* top_p,
    int64_t* samples,
    curandState* states,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
);

// Host function to perform sorting and sampling
void run_sampling_kernel(
    const float* probs,
    const int* top_k,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
);

#include "kernel.h"
#include <curand_kernel.h>
#include <math_constants.h>
#include <thrust/device_vector.h>
#include <thrust/sort.h>
#include <thrust/sequence.h>
#include <thrust/copy.h>
#include <thrust/execution_policy.h>
#include <thrust/iterator/counting_iterator.h>
#include <thrust/iterator/transform_iterator.h>
#include <thrust/functional.h>

// Initialize random states kernel
__global__ void init_random_states_kernel_impl(curandState* states, int batch_size, unsigned long long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < batch_size) {
        curand_init(seed, idx, 0, &states[idx]);
    }
}

void init_random_states_kernel(
    curandState* states,
    int batch_size,
    unsigned long long seed,
    cudaStream_t stream
) {
    int threads = 256;
    int blocks = (batch_size + threads - 1) / threads;
    init_random_states_kernel_impl<<<blocks, threads, 0, stream>>>(states, batch_size, seed);
}

// Sort probabilities using thrust - optimized version with proper per-row indices
void sort_probs_kernel(
    float* probs,
    int* indices,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
) {
    // Initialize indices for each row (0 to vocab_size-1 for each row)
    thrust::device_vector<int> d_row_indices(vocab_size);
    thrust::sequence(thrust::device, d_row_indices.begin(), d_row_indices.end(), 0);

    // Copy indices to device array for each row
    for (int i = 0; i < batch_size; ++i) {
        cudaMemcpyAsync(indices + i * vocab_size, thrust::raw_pointer_cast(d_row_indices.data()), 
                       vocab_size * sizeof(int), 
                       cudaMemcpyDeviceToDevice, stream);
    }

    // Sort each row in parallel using a kernel with thrust
    // We need to sort each row separately
    thrust::device_ptr<float> probs_ptr(probs);
    thrust::device_ptr<int> indices_ptr(indices);

    // For each batch, sort the corresponding vocab_size elements
    for (int i = 0; i < batch_size; ++i) {
        thrust::device_ptr<float> row_probs = thrust::device_pointer_cast(probs + i * vocab_size);
        thrust::device_ptr<int> row_indices = thrust::device_pointer_cast(indices + i * vocab_size);

        thrust::sort_by_key(
            thrust::device,
            row_probs, row_probs + vocab_size,
            row_indices,
            thrust::greater<float>()
        );
    }
}

// Main sampling kernel - corrected to match reference implementation exactly
__global__ void top_k_top_p_sampling_kernel(
    const float* probs_sorted,
    const int* indices_sorted,
    const int* top_k,
    const float* top_p,
    int64_t* samples,
    curandState* states,
    int batch_size,
    int vocab_size
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size) return;

    // Pointers to current row
    const float* row_probs = probs_sorted + idx * vocab_size;
    const int* row_indices = indices_sorted + idx * vocab_size;

    int k = top_k[idx];
    float p = top_p[idx];
    curandState* state = states + idx;

    // Step 1: Apply Top-K filtering
    int cutoff_k = vocab_size;
    if (k > 0 && k < vocab_size) {
        cutoff_k = k;
    }

    // Step 2: Renormalize after top-K filtering (MATCHES REFERENCE)
    float sum_k = 0.0f;
    for (int i = 0; i < cutoff_k; ++i) {
        sum_k += row_probs[i];
    }

    float renorm_k = 1.0f;
    if (sum_k > 0.0f) {
        renorm_k = 1.0f / sum_k;
    }

    // Step 3: Apply Top-P filtering on the top-K filtered distribution
    int cutoff_p = cutoff_k;
    if (p <= 0.0f) {
        // Just argmax - take the first (highest probability) token
        cutoff_p = 1;
    } else if (p < 1.0f) {
        // Calculate cumsum on top-K filtered and renormalized probs
        float cumsum = 0.0f;
        int found = 0;
        for (int i = 0; i < cutoff_k; ++i) {
            float prob = row_probs[i] * renorm_k;
            cumsum += prob;
            // Keep tokens where cumsum <= p (MATCHES REFERENCE: to_remove = cdf > p)
            if (cumsum > p) {
                cutoff_p = i;  // Keep only up to this index (exclusive)
                found = 1;
                break;
            }
        }
        // If cumsum never exceeds p, keep all top-k tokens
        if (!found) cutoff_p = cutoff_k;
    }

    // Step 4: Final cutoff is the top-p cutoff (which is already <= top-k)
    int final_cutoff = cutoff_p;

    // Step 5: Renormalize the final distribution (MATCHES REFERENCE)
    float sum_final = 0.0f;
    for (int i = 0; i < final_cutoff; ++i) {
        sum_final += row_probs[i];
    }

    float renorm_final = 1.0f;
    if (sum_final > 0.0f) {
        renorm_final = 1.0f / sum_final;
    } else {
        // If all probabilities are zero, uniform distribution
        renorm_final = 1.0f / (final_cutoff > 0 ? (float)final_cutoff : 1.0f);
    }

    // Step 6: Sample using inverse transform sampling
    float r = curand_uniform(state);

    float cumsum = 0.0f;
    int sampled_idx = row_indices[0];

    for (int i = 0; i < final_cutoff; ++i) {
        float prob = row_probs[i] * renorm_final;
        cumsum += prob;
        if (r < cumsum) {
            sampled_idx = row_indices[i];
            break;
        }
    }

    // Handle edge case where r >= cumsum due to floating point
    if (cumsum <= r && final_cutoff > 0) {
        sampled_idx = row_indices[final_cutoff - 1];
    }

    samples[idx] = (int64_t)sampled_idx;
}

void launch_top_k_top_p_sampling_kernel(
    const float* probs_sorted,
    const int* indices_sorted,
    const int* top_k,
    const float* top_p,
    int64_t* samples,
    curandState* states,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
) {
    int threads = 256;
    int blocks = (batch_size + threads - 1) / threads;

    top_k_top_p_sampling_kernel<<<blocks, threads, 0, stream>>>(
        probs_sorted, indices_sorted, top_k, top_p, samples, states, batch_size, vocab_size
    );
}

// Host function to perform sorting and sampling with optimized memory management
void run_sampling_kernel(
    const float* probs,
    const int* top_k,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
) {
    // Allocate device memory for sorted data
    float* d_probs_sorted = nullptr;
    int* d_indices_sorted = nullptr;
    curandState* d_states = nullptr;

    size_t vocab_bytes = vocab_size * sizeof(float);
    size_t indices_bytes = vocab_size * sizeof(int);
    size_t total_probs_bytes = batch_size * vocab_bytes;
    size_t total_indices_bytes = batch_size * indices_bytes;

    cudaError_t err;
    err = cudaMalloc(&d_probs_sorted, total_probs_bytes);
    if (err != cudaSuccess) {
        return;
    }
    err = cudaMalloc(&d_indices_sorted, total_indices_bytes);
    if (err != cudaSuccess) {
        cudaFree(d_probs_sorted);
        return;
    }
    err = cudaMalloc(&d_states, batch_size * sizeof(curandState));
    if (err != cudaSuccess) {
        cudaFree(d_probs_sorted);
        cudaFree(d_indices_sorted);
        return;
    }

    // Copy probs to sorted buffer
    err = cudaMemcpyAsync(d_probs_sorted, probs, total_probs_bytes, cudaMemcpyDeviceToDevice, stream);
    if (err != cudaSuccess) {
        cudaFree(d_probs_sorted);
        cudaFree(d_indices_sorted);
        cudaFree(d_states);
        return;
    }

    // Sort each row descending
    sort_probs_kernel(d_probs_sorted, d_indices_sorted, batch_size, vocab_size, stream);

    // Initialize Random States using kernel
    init_random_states_kernel(d_states, batch_size, 12345ULL, stream);

    // Launch Sampling Kernel
    launch_top_k_top_p_sampling_kernel(
        d_probs_sorted,
        d_indices_sorted,
        top_k,
        top_p,
        samples,
        d_states,
        batch_size,
        vocab_size,
        stream
    );

    // Synchronize to ensure completion before cleanup
    cudaStreamSynchronize(stream);

    // Cleanup
    cudaFree(d_probs_sorted);
    cudaFree(d_indices_sorted);
    cudaFree(d_states);
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <vector>
#include <iostream>
#include "kernel.h"

// Helper to check CUDA errors
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            throw std::runtime_error(std::string("CUDA error: ") + cudaGetErrorString(err)); \
        } \
    } while(0)

torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_k,
    torch::Tensor top_p,
    torch::Tensor samples
) {
    // Validate inputs
    TORCH_CHECK(probs.device().is_cuda(), "probs must be on CUDA");
    TORCH_CHECK(top_k.device().is_cuda(), "top_k must be on CUDA");
    TORCH_CHECK(top_p.device().is_cuda(), "top_p must be on CUDA");
    TORCH_CHECK(samples.device().is_cuda(), "samples must be on CUDA");
    TORCH_CHECK(probs.dtype() == torch::kFloat32, "probs must be float32");
    TORCH_CHECK(top_k.dtype() == torch::kInt32, "top_k must be int32");
    TORCH_CHECK(top_p.dtype() == torch::kFloat32, "top_p must be float32");
    TORCH_CHECK(samples.dtype() == torch::kInt64, "samples must be int64");

    int batch_size = probs.size(0);
    int vocab_size = probs.size(1);
    TORCH_CHECK(vocab_size == VOCAB_SIZE, "vocab_size must be " + std::to_string(VOCAB_SIZE));
    TORCH_CHECK(top_k.size(0) == batch_size, "top_k size must match batch_size");
    TORCH_CHECK(top_p.size(0) == batch_size, "top_p size must match batch_size");
    TORCH_CHECK(samples.size(0) == batch_size, "samples size must match batch_size");

    // Launch the CUDA kernel
    run_sampling_kernel(
        probs.data_ptr<float>(),
        top_k.data_ptr<int>(),
        top_p.data_ptr<float>(),
        samples.data_ptr<int64_t>(),
        batch_size,
        vocab_size,
        0 // Default stream
    );

    // Check for any CUDA errors
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Top-K Top-P Sampling Kernel");
}
